# locustfile.py — Load test for contract-analysis-agent API
from locust import HttpUser, task, between
import random, json

# Realistic input lengths sampled from beta traffic distribution
INPUT_LENGTHS = [
    ("short", 0.30, 2000),    # 30% short contracts, ~2k tokens
    ("medium", 0.55, 6000),   # 55% medium, ~6k tokens
    ("long", 0.15, 10000),    # 15% long contracts, ~10k tokens
]

def sample_contract_size() -> int:
    """Sample contract size from beta distribution."""
    r = random.random()
    cumulative = 0.0
    for _, weight, size in INPUT_LENGTHS:
        cumulative += weight
        if r <= cumulative:
            return size
    return INPUT_LENGTHS[-1][2]

class ContractAnalysisUser(HttpUser):
    wait_time = between(0.5, 2.0)  # simulates realistic inter-request time

    @task(10)
    def analyze_contract(self):
        size = sample_contract_size()
        # In a real load test, use actual contract samples; here we simulate length
        payload = {
            "document_id": f"doc_{random.randint(1, 10000)}",
            "content_length_tokens": size,
            "analysis_type": random.choice(["full", "risk_only", "summary"]),
            "user_id": f"user_{random.randint(1, 500)}",
        }
        with self.client.post(
            "/api/v1/analyze",
            json=payload,
            catch_response=True,
            stream=True,
        ) as response:
            if response.status_code == 200:
                response.success()
            elif response.status_code == 429:
                response.failure(f"Rate limited: {response.text}")
            else:
                response.failure(f"Error {response.status_code}: {response.text}")

    @task(1)
    def health_check(self):
        self.client.get("/health")

# Run: locust --headless -u 90 -r 9 --run-time 300s  (2x peak = 90 users)
